/**
 * Page templates — define the structural skeleton Claude fills in.
 *
 * Setup slots are fixed (Claude provides content, not structure).
 * Engage is a palette — Claude picks blocks from the allowed list.
 * Resolve is always code-appended and never generated by Claude.
 *
 * `overrides` on a palette entry are enforced in briefToBlocks regardless of
 * what Claude outputs. `defaults` carry soft constraints (item counts, caps)
 * also enforced in code. Claude is told about both via templateToPrompt.
 */

import type { PageBrief } from './types'

export type ProductType = 'hardware' | 'software'

export type SetupSlot = {
  component: string
  required: boolean
  hint: string
}

export type PaletteEntry = {
  component: string
  hint: string
  max?: number
  /** Prop values merged into blockOptions in briefToBlocks — Claude cannot override these */
  overrides?: Record<string, unknown>
  /** Soft constraints enforced in briefToBlocks (item counts, caps) */
  defaults?: {
    itemCount?: number  // default number of items if Claude provides none
    maxItems?: number   // hard cap on items array length
  }
}

export type PageTemplate = {
  id: string
  name: string
  productType: ProductType
  /** Drives the purchase CTA label and destination in the Resolve section */
  resolveCta: {
    label: string
    destination: string
  }
  setup: SetupSlot[]
  engage: {
    min: number
    max: number
    /** Ordered by preference — Claude should favour entries listed first */
    palette: PaletteEntry[]
  }
}

