export function getTemplate(id: string): PageTemplate | null {
  return TEMPLATES[id] ?? null
}

// ─── Override application ─────────────────────────────────────────────────────

/**
 * Apply palette overrides and item caps to a brief's engage sections.
 * Matches each section to the most specific palette entry by component +
 * discriminating blockOptions fields, then merges overrides and caps items.
 */
export function applyTemplateOverrides(brief: PageBrief, template: PageTemplate): PageBrief {
  const palette = template.engage.palette
  const DISCRIMINATORS = ['variant', 'paragraphColumnLayout'] as const

  const sections = brief.sections.map((section) => {
    if (section.narrativeRole !== 'engage') return section

    const candidates = palette.filter((e) => e.component === section.component)
    if (!candidates.length) return section

    const opts = (section.blockOptions ?? {}) as Record<string, unknown>

    // Find the palette entry whose discriminating overrides best match Claude's output
    const match =
      candidates.find((entry) => {
        const ov = entry.overrides ?? {}
        return DISCRIMINATORS.every((k) => {
          if (ov[k] === undefined) return true
          return opts[k] === ov[k] || opts[k] === undefined || opts[k] === null
        })
      }) ?? candidates[0]

    // Merge overrides into blockOptions
    const newBlockOptions = { ...(section.blockOptions ?? {}), ...(match.overrides ?? {}) }

    // Cap items array to maxItems
    const maxItems = match.defaults?.maxItems
    const slots = section.contentSlots
    const newItems =
      maxItems && Array.isArray(slots.items) && slots.items.length > maxItems
        ? slots.items.slice(0, maxItems)
        : slots.items

    return {
      ...section,
      blockOptions: newBlockOptions,
      contentSlots: newItems !== slots.items ? { ...slots, items: newItems } : slots,
    }
  })

  return { ...brief, sections }
}

// ─── Prompt serialisation ─────────────────────────────────────────────────────

export function templateToPrompt(t: PageTemplate): string {
  const setupLines = t.setup
    .map((s, i) => `  ${i + 1}. ${s.component}${s.required ? '' : ' (optional)'} — ${s.hint}`)
    .join('\n')

  const paletteLines = t.engage.palette
    .map((p) => {
      const ov = p.overrides ?? {}
      const ovNote = Object.keys(ov).length
        ? ` [enforced: ${Object.entries(ov).map(([k, v]) => `${k}=${v}`).join(', ')}]`
        : ''
      const defNote = p.defaults?.itemCount ? ` [default ${p.defaults.itemCount} items]` : ''
      const maxItemsNote = p.defaults?.maxItems ? ` [max ${p.defaults.maxItems} items]` : ''
      return `  - ${p.component}${p.max ? ` (max ${p.max}×)` : ''}${ovNote}${defNote}${maxItemsNote}: ${p.hint}`
    })
    .join('\n')

  return `Template: ${t.name}

SETUP (fixed order — provide content for each slot):
${setupLines}

ENGAGE (pick ${t.engage.min}–${t.engage.max} blocks):
${paletteLines}

Do not use components outside this palette.`
}
